/// <summary>
///    The <c>InventValueReportContract</c> class handles the parameters for the inventory value report.
///    changes for closing ctock report
/// </summary>
[
    DataContractAttribute, SysOperationAlwaysInitializeAttribute,
    SysOperationContractProcessing(classStr(ETG_ClosingStockValUIBuilder))
]


public class ETG_ClosingStockValContract //implements SysOperationValidatable
{

    TransDate           CurDate;
    DateOnhand          PerDate;
    NoYes               config,size,color,style,site , warehouse,location,batchnumber,serialNumber; 




}

